#include <stdio.h>
#include <stdbool.h>
#define MAX 705

int main() {
    int M, N;
    while (scanf("%d %d", &M, &N) == 2 && (M != 0 || N != 0)) {
        char grid[MAX][MAX];
        for (int i = 0; i < M; i++) {
            scanf("%s", grid[i]);
        }
        int count = 0;
        bool underAttack[MAX][MAX];
        for (int i = 0; i < M; i++) {
            for (int j = 0; j < N; j++) {
                underAttack[i][j] = false;
            }
        }
        // Mark cells under attack by existing guns
        for (int i = 0; i < M; i++) {
            for (int j = 0; j < N; j++) {
                if (grid[i][j] == 'G') {
                    for (int x = -2; x <= 2; x += 4) {
                        for (int y = -2; y <= 2; y += 4) {
                            int nx = i + x, ny = j + y;
                            if (nx >= 0 && nx < M && ny >= 0 && ny < N && grid[nx][ny] != 'P') {
                                underAttack[nx][ny] = true;
                            }
                        }
                    }
                }
            }
        }
        // Try to add guns to free cells not under attack
        for (int i = 0; i < M; i++) {
            for (int j = 0; j < N; j++) {
                if (grid[i][j] == 'F' && !underAttack[i][j]) {
                    grid[i][j] = 'G';
                    count++;
                    // Update underAttack
                    for (int x = -2; x <= 2; x += 4) {
                        for (int y = -2; y <= 2; y += 4) {
                            int nx = i + x, ny = j + y;
                            if (nx >= 0 && nx < M && ny >= 0 && ny < N && grid[nx][ny] != 'P') {
                                underAttack[nx][ny] = true;
                            }
                        }
                    }
                }
            }
        }
        printf("%d\n", count);
    }
    return 0;
}

